const userMessage = ($('Chat Trigger').first().json.chatInput || '').trim();
const currentMode = $json.current_mode || null;
const storedBizId = $json.selected_business_id || null;
if (currentMode === 'in_setup' && storedBizId) {
  return [{ json: { action: 'select_existing', business_id: storedBizId, output: null } }];
}
const allItems = $('Load Projects').all();
const projects = allItems
  .filter(function(item) { return item.json && item.json.id; })
  .map(function(item, i) {
    return { index: i + 1, id: item.json.id, name: item.json.name || '(unnamed)' };
  });
function buildMenu(header) {
  var lines = projects.map(function(p) { return '(' + p.index + ') ' + p.name; });
  var body = lines.length > 0 ? lines.join('\n') : '(no projects yet)';
  return header + '\n\n' + body + '\n\n(0) Create new project';
}
if (currentMode === 'await_project_name') {
  if (!userMessage) {
    return [{ json: { action: 'create_new', output: 'What is the name of the new project?', projects: projects } }];
  }
  return [{ json: { action: 'save_name', project_name: userMessage, output: userMessage, projects: projects } }];
}
if (!userMessage) {
  return [{ json: { action: 'show_list', output: buildMenu('Choose a project (type number):'), projects: projects } }];
}
var trimmed = userMessage.replace(/^\s+|\s+$/g, '');
var num = parseInt(trimmed, 10);
if (isNaN(num) || String(num) !== trimmed) {
  return [{ json: { action: 'show_list', output: buildMenu('Please choose a valid number from the list.'), projects: projects } }];
}
if (num === 0) {
  return [{ json: { action: 'create_new', output: 'What is the name of the new project?', projects: projects } }];
}
var selected = null;
for (var i = 0; i < projects.length; i++) {
  if (projects[i].index === num) { selected = projects[i]; break; }
}
if (!selected) {
  return [{ json: { action: 'show_list', output: buildMenu('Please choose a valid number from the list.'), projects: projects } }];
}
return [{ json: { action: 'select_existing', business_id: selected.id, output: 'Loading project: ' + selected.name + '...', projects: projects } }];

// ─── INPUTS ───────────────────────────────────────────────────────────────────
const userMessage       = $('Chat Trigger').first().json.chatInput || '';
const business          = $('Resolve Business').first().json;
const businessId        = business.id || null;

const setupCompleted    = business.setup_completed;
const currentStage      = business.setup_stage || null;
// read optional cross-workflow fields defensively
const trainingCompleted = business.training_completed || false;

let setupDraft = {};
try {
  setupDraft = typeof business.setup_draft === 'string'
    ? JSON.parse(business.setup_draft || '{}')
    : (business.setup_draft || {});
} catch(e) { setupDraft = {}; }

// ─── QUESTIONS ────────────────────────────────────────────────────────────────
const QUESTIONS = {
  business_model:
    'How does a customer buy from you in practice?\n1. Need discovery + custom offer\n2. Fixed-price products or services\n3. Packages or subscriptions\n4. Booking by time / appointment\n5. Other',
  primary_goal:
    'What is the main action you want a new lead to take?\n1. Book a call\n2. Leave details\n3. Make a purchase\n4. Continue chatting to clarify needs',
  conversation_priority:
    'What matters most to you in the first conversation?\n1. Understand the need\n2. Filter irrelevant leads\n3. Close quickly\n4. Give information only',
  service_type_1:      'What main services do you provide?',
  service_type_2:      'What information is important for you to understand before moving forward with a lead?',
  service_type_3:      'What is usually the first question you ask to understand the lead?',
  product_type_1:      'What main products or categories do you sell?',
  product_type_2:      'How do you usually understand which product fits the customer?',
  product_type_3:      'What questions do customers usually ask before buying?',
  subscription_type_1: 'What plans or packages do you offer?',
  subscription_type_2: 'How do you decide which plan fits a customer?',
  subscription_type_3: 'What usually makes customers hesitate between plans?',
  booking_type_1:      'What types of appointments / treatments / services can be booked?',
  booking_type_2:      'What is important for you to understand before booking?',
  booking_type_3:      'Are there cases where it is not right to book immediately?',
  other_type_1:        'Briefly describe how your sales / signup flow works.',
  other_type_2:        'What information is important for you to understand from a new lead?',
  other_type_3:        'What is the best first question to ask them?',
  persona_tone:        'How do you want to sound with customers? Casual / professional / direct / friendly / other',
  answer_length:       'Do you prefer very short, medium, or slightly more detailed replies?',
  emoji_style:         'Do you want emojis? none / light / natural / free',
  faq:                 'Give 2-3 questions customers ask often, and how you usually answer them.',
  objections:          'What are 2-3 common objections you hear, and how do you usually respond?',
  forbidden_claims:    'Are there things you do not want to say or promise in an initial conversation?',
  escalation_rules:    'In which cases should the conversation be handed off to a real person?',
  final_note:          'If there is one thing the assistant must not miss in the way you talk to customers, what is it?',
};

// ─── STAGE → DRAFT PATH ───────────────────────────────────────────────────────
// business_model handled separately via normalizeBusinessType
const STAGE_PATHS = {
  primary_goal:         'routing.primary_goal',
  conversation_priority:'routing.conversation_priority',
  service_type_1:       'business_profile.services',
  service_type_2:       'business_profile.required_info',
  service_type_3:       'business_profile.first_question',
  product_type_1:       'business_profile.products',
  product_type_2:       'business_profile.selection_logic',
  product_type_3:       'business_profile.common_prepurchase_questions',
  subscription_type_1:  'business_profile.plans',
  subscription_type_2:  'business_profile.plan_fit_logic',
  subscription_type_3:  'business_profile.common_objections',
  booking_type_1:       'business_profile.booking_types',
  booking_type_2:       'business_profile.required_info',
  booking_type_3:       'business_profile.pre_booking_filters',
  other_type_1:         'business_profile.sales_flow_summary',
  other_type_2:         'business_profile.required_info',
  other_type_3:         'business_profile.first_question',
  persona_tone:         'persona.tone',
  answer_length:        'persona.answer_length',
  emoji_style:          'persona.emoji_style',
  faq:                  'knowledge.faq',
  objections:           'knowledge.objection_handling',
  forbidden_claims:     'guardrails.forbidden_claims',
  escalation_rules:     'guardrails.escalation_rules',
  final_note:           'persona.must_not_miss',
};

// PATCH 4: Stages whose answers must be stored as arrays (list-like fields)
const ARRAY_STAGES = {
  service_type_1:      true,
  service_type_2:      true,
  product_type_1:      true,
  product_type_3:      true,
  subscription_type_1: true,
  booking_type_1:      true,
  booking_type_2:      true,
  booking_type_3:      true,
  other_type_2:        true,
};
// Fields remaining plain text: first_question, selection_logic, plan_fit_logic,
// sales_flow_summary, common_objections

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function setPath(obj, path, value) {
  const keys = path.split('.');
  let cur = obj;
  for (let i = 0; i < keys.length - 1; i++) {
    if (!cur[keys[i]] || typeof cur[keys[i]] !== 'object') cur[keys[i]] = {};
    cur = cur[keys[i]];
  }
  cur[keys[keys.length - 1]] = value;
  return obj;
}

function getPath(obj, path) {
  return path.split('.').reduce(function(o, k) { return (o && o[k] !== undefined ? o[k] : null); }, obj);
}

// PATCH 2: Strict validation — only accept 1-5 or exact canonical keywords
function isValidBusinessModel(raw) {
  const s = String(raw || '').trim().toLowerCase();
  return ['1','2','3','4','5','service','product','subscription','booking','other'].indexOf(s) !== -1;
}

// Normalize valid answer to canonical value
function normalizeBusinessType(raw) {
  const s = String(raw || '').trim().toLowerCase();
  if (s === '1' || s === 'service')      return 'service';
  if (s === '2' || s === 'product')      return 'product';
  if (s === '3' || s === 'subscription') return 'subscription';
  if (s === '4' || s === 'booking')      return 'booking';
  return 'other';
}

function getBranch(draft) {
  const choice = String(getPath(draft, 'routing.business_type_choice') || '').trim().toLowerCase();
  if (choice === 'service')      return 'service';
  if (choice === 'product')      return 'product';
  if (choice === 'subscription') return 'subscription';
  if (choice === 'booking')      return 'booking';
  return 'other';
}

function getNextStage(stage, draft) {
  const branch = getBranch(draft);
  const FLOW = {
    business_model:        'primary_goal',
    primary_goal:          'conversation_priority',
    conversation_priority: branch + '_type_1',
    [branch + '_type_1']:  branch + '_type_2',
    [branch + '_type_2']:  branch + '_type_3',
    [branch + '_type_3']:  'persona_tone',
    persona_tone:          'answer_length',
    answer_length:         'emoji_style',
    emoji_style:           'faq',
    faq:                   'objections',
    objections:            'forbidden_claims',
    forbidden_claims:      'escalation_rules',
    escalation_rules:      'final_note',
    final_note:            'review',
    review:                'completed',
  };
  return FLOW[stage] || 'completed';
}

function buildReviewSummary(draft) {
  const r  = draft.routing          || {};
  const bp = draft.business_profile  || {};
  const p  = draft.persona           || {};
  const k  = draft.knowledge         || {};
  const g  = draft.guardrails        || {};

  const bpFormatted = Object.entries(bp)
    .map(function(e) {
      const val = Array.isArray(e[1]) ? e[1].join(', ') : String(e[1]);
      return '  ' + e[0] + ': ' + val;
    })
    .join('\n');

  return [
    'Here is your setup summary:',
    '',
    'Business Type: ' + (r.business_type_choice || '-'),
    'Primary Goal: ' + (r.primary_goal || '-'),
    'Conversation Priority: ' + (r.conversation_priority || '-'),
    '',
    'Business Profile:',
    bpFormatted || '  (none)',
    '',
    'Persona - Tone: ' + (p.tone || '-') + ' | Length: ' + (p.answer_length || '-') + ' | Emoji: ' + (p.emoji_style || '-'),
    'Must not miss: ' + (p.must_not_miss || '-'),
    '',
    'FAQ: ' + (k.faq || '-'),
    'Objections: ' + (k.objection_handling || '-'),
    '',
    'Forbidden Claims: ' + (g.forbidden_claims || '-'),
    'Escalation Rules: ' + (g.escalation_rules || '-'),
    '',
    'Type yes to save and complete setup, or no to restart.',
  ].join('\n');
}

// PATCH 5: Structured converters
// faq / objection_handling -> [{ text: "..." }]
function toTextObjects(val) {
  if (!val) return [];
  if (Array.isArray(val)) {
    return val.map(function(v) {
      return (v && typeof v === 'object' && v.text) ? v : { text: String(v) };
    });
  }
  return [{ text: String(val) }];
}
// forbidden_claims / escalation_rules -> ["..."]
function toStringArray(val) {
  if (!val) return [];
  if (Array.isArray(val)) return val.map(String);
  return [String(val)];
}

function buildCommitData(draft) {
  const r  = draft.routing          || {};
  const bp = draft.business_profile  || {};
  const p  = draft.persona           || {};
  const k  = draft.knowledge         || {};
  const g  = draft.guardrails        || {};

  const personaPrompt = [
    'Tone: ' + (p.tone || 'professional') + '.',
    'Answer length: ' + (p.answer_length || 'medium') + '.',
    'Emoji usage: ' + (p.emoji_style || 'none') + '.',
    p.must_not_miss ? 'Must not miss: ' + p.must_not_miss + '.' : '',
  ].filter(Boolean).join(' ');

  // PATCH 6: qualification_rules as structured JSON
  const qualRules = {
    conversation_priority: r.conversation_priority || '',
    required_info:         Array.isArray(bp.required_info) ? bp.required_info : (bp.required_info ? [bp.required_info] : []),
    first_question:        bp.first_question || '',
  };

  // PATCH 6: cta_rules as structured JSON
  const ctaRules = {
    primary_goal: r.primary_goal || '',
  };

  // approved_knowledge built for optional use
  const approvedKnowledge = {
    setup_summary: {
      business_type:      r.business_type_choice || 'other',
      business_profile:   bp,
      faq:                toTextObjects(k.faq),
      objection_handling: toTextObjects(k.objection_handling),
    },
  };

  // runtime_ready — false unless training_completed is already true
  const runtimeReady = (trainingCompleted === true);

  return {
    business_type:       r.business_type_choice || 'other',
    business_profile:    bp,
    persona_prompt:      personaPrompt,
    qualification_rules: qualRules,
    cta_rules:           ctaRules,
    faq:                 toTextObjects(k.faq),
    objection_handling:  toTextObjects(k.objection_handling),
    forbidden_claims:    toStringArray(g.forbidden_claims),
    escalation_rules:    toStringArray(g.escalation_rules),
    optional: {
      approved_knowledge: approvedKnowledge,
      runtime_ready:      runtimeReady,
    },
  };
}

// PATCH 1: Lightweight debug/state object attached to every return
function makeDebug(curStage, nxtStage, action) {
  return {
    current_stage: curStage,
    next_stage:    nxtStage,
    action:        action,
    user_message:  userMessage,
  };
}

// ─── MAIN LOGIC ───────────────────────────────────────────────────────────────

if (setupCompleted) {
  return [{ json: {
    output:         'Setup is already completed for this business. No further changes needed.',
    response:       'Setup is already completed for this business. No further changes needed.',
    action:         'none',
    nextStage:      'completed',
    setupDraftJson: JSON.stringify(setupDraft),
    commitData:     null,
    businessId,
    debug:          makeDebug(currentStage, 'completed', 'none'),
  }}];
}

// First run — no stage set yet. Return opening question without saving any answer.
if (!currentStage || currentStage === '') {
  return [{ json: {
    output:         QUESTIONS['business_model'],
    response:       QUESTIONS['business_model'],
    action:         'save_draft',
    nextStage:      'business_model',
    setupDraftJson: JSON.stringify(setupDraft),
    commitData:     null,
    businessId,
    debug:          makeDebug(null, 'business_model', 'save_draft'),
  }}];
}

// PATCH 3: Review stage — expanded confirmation set, explicit unclear handling
if (currentStage === 'review') {
  const answer       = userMessage.trim().toLowerCase();
  const positiveSet  = ['yes','y','\u05DB\u05DF','\u05E1\u05D2\u05D5\u05E8','\u05D9\u05D0\u05DC\u05DC\u05D4','approve','approved'];
  const negativeSet  = ['no','n','\u05DC\u05D0','restart','\u05DE\u05D7\u05D3\u05E9'];

  if (positiveSet.indexOf(answer) !== -1) {
    const commitData = buildCommitData(setupDraft);
    return [{ json: {
      output:         'Setup completed! Your business profile has been saved and your agent is ready.',
      response:       'Setup completed! Your business profile has been saved and your agent is ready.',
      action:         'commit',
      nextStage:      'completed',
      setupDraftJson: '{}',
      commitData,
      businessId,
      debug:          makeDebug('review', 'completed', 'commit'),
    }}];
  }

  if (negativeSet.indexOf(answer) !== -1) {
    return [{ json: {
      output:         'No problem. Let us start over.\n\n' + QUESTIONS['business_model'],
      response:       'No problem. Let us start over.\n\n' + QUESTIONS['business_model'],
      action:         'save_draft',
      nextStage:      'business_model',
      setupDraftJson: '{}',
      commitData:     null,
      businessId,
      debug:          makeDebug('review', 'business_model', 'save_draft'),
    }}];
  }

  // Unclear — do not advance or restart
  return [{ json: {
    output:         'Please reply with yes or no.',
    response:       'Please reply with yes or no.',
    action:         'save_draft',
    nextStage:      'review',
    setupDraftJson: JSON.stringify(setupDraft),
    commitData:     null,
    businessId,
    debug:          makeDebug('review', 'review', 'save_draft'),
  }}];
}

// Normal stage: validate if needed, save reply, advance, return next question
let updatedDraft = JSON.parse(JSON.stringify(setupDraft));

if (currentStage === 'business_model') {
  // PATCH 2: Reject invalid input — do not advance, do not overwrite draft
  if (!isValidBusinessModel(userMessage)) {
    return [{ json: {
      output:         'Please choose a valid option: 1-5.',
      response:       'Please choose a valid option: 1-5.',
      action:         'save_draft',
      nextStage:      'business_model',
      setupDraftJson: JSON.stringify(setupDraft),
      commitData:     null,
      businessId,
      debug:          makeDebug('business_model', 'business_model', 'save_draft'),
    }}];
  }
  updatedDraft = setPath(updatedDraft, 'routing.business_type_choice', normalizeBusinessType(userMessage));
} else {
  const draftPath = STAGE_PATHS[currentStage];
  if (draftPath) {
    // PATCH 4: Wrap list-like fields as single-item arrays
    const value = ARRAY_STAGES[currentStage] ? [userMessage] : userMessage;
    updatedDraft = setPath(updatedDraft, draftPath, value);
  }
}

const nextStage = getNextStage(currentStage, updatedDraft);

let nextQuestion;
if (nextStage === 'review') {
  nextQuestion = buildReviewSummary(updatedDraft);
} else if (nextStage === 'completed') {
  nextQuestion = 'All done!';
} else {
  nextQuestion = QUESTIONS[nextStage] || ('(unknown stage: ' + nextStage + ')');
}

return [{ json: {
  output:         nextQuestion,
  response:       nextQuestion,
  action:         'save_draft',
  nextStage,
  setupDraftJson: JSON.stringify(updatedDraft),
  commitData:     null,
  businessId,
  debug:          makeDebug(currentStage, nextStage, 'save_draft'),
}}];
